// Validate project record exists and extract key fields
// T016: Added industry + RE branding fields passthrough
const input = $input.first().json;

// Check if Airtable returned an error or empty
if (!input || !input.id || input.error) {
  return [{ json: { error: true, message: `Project not found or Airtable error. Input: ${JSON.stringify(input).slice(0, 200)}` } }];
}

const projectName = input['Project Name'];
if (!projectName) {
  return [{ json: { error: true, message: 'Project record has no Project Name field' } }];
}

return [{ json: {
  error: false,
  projectRecordId: input.id,
  projectName: projectName,
  brandName: input['Brand Name'] || projectName,
  pipelineLog: input['Pipeline Log'] || '',
  status: input['Status'] || '',
  industry: (input['Industry'] || '').toLowerCase().trim(),
  agentBranding: {
    logoUrl: input['Agent Logo URL'] || '',
    brokerageName: input['Brokerage Name'] || '',
    mlsNumber: input['MLS Number'] || ''
  }
} }];

// Build error log entry for project not found
const data = $('Code — Validate Project').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const message = data.message || 'Unknown project validation error';
const logEntry = `[${now}] \u2717 REEL ERROR: ${message}`;

return [{ json: {
  logEntry,
  errorMessage: message,
  statusReset: 'videos_generated',
  projectRecordId: null,
  pipelineLog: ''
} }];

// Return error response to webhook caller
const data = $input.first().json;
return [{ json: {
  success: false,
  error: data.errorMessage || 'Reel assembly failed',
  stage: 'validation'
} }];

// V2: Pre-flight check — 4 Veo 3.1 clips + music
// Returns error object instead of throwing
const videoRecords = $('Airtable \u2014 Fetch Video Records').all();
const reelItems = $('Airtable \u2014 Fetch Reel Record').all();
const project = $('Code \u2014 Validate Project').first().json;
const projectId = project.projectRecordId.replace(/[^a-zA-Z0-9]/g, '');

// Validate reel record exists
if (!reelItems.length || !reelItems[0].json.id) {
  return [{ json: { error: true, message: `No Reel record found for project '${project.projectName}'` } }];
}
const reelRecord = reelItems[0].json;

// Validate 4 video records
if (videoRecords.length < 4) {
  return [{ json: { error: true, message: `Expected 4 video records, found ${videoRecords.length}` } }];
}

// Sort by phase number
const sorted = videoRecords.sort((a, b) =>
  a.json['Phase Number'] - b.json['Phase Number']
);

// Extract Drive File IDs for 4 clips
const driveFileIds = sorted.map(r => r.json['Drive File ID']);
for (let i = 0; i < 4; i++) {
  if (!driveFileIds[i]) {
    return [{ json: { error: true, message: `Video ${i + 1} (Phase ${sorted[i].json['Phase Number']}) missing Drive File ID` } }];
  }
}

// Get music track selection
const musicTrack = reelRecord['Music Track'] || 'swing_pop';

const musicDriveIds = {
  'swing_pop': '1Wx2Je-Ohtl9Wwk8Ga4J8IXn-IP58JpVV',
  'ambient_build': '1BGL2u2ZQl9LROg5-6vpWAvvU-B8NX-XW',
  'cinematic_progress': '16Li5bzMLaLvAZSbDJ9tePfBgB-qNlhuz',
  're_luxury_ambient': 'REPLACE_WITH_RE_MUSIC_DRIVE_ID'
};

const musicDriveId = musicDriveIds[musicTrack];
if (!musicDriveId || musicDriveId.startsWith('REPLACE')) {
  return [{ json: { error: true, message: `Music track '${musicTrack}' Drive ID not configured` } }];
}

const workDir = `/tmp/tht-${projectId}`;

return [{
  json: {
    error: false,
    workDir,
    projectId,
    projectRecordId: project.projectRecordId,
    reelRecordId: reelRecord.id,
    driveFileIds,
    musicDriveId,
    musicTrack,
    brandName: project.brandName,
    clipCount: 4,
    pipelineLog: project.pipelineLog,
    industry: project.industry || '',
    agentBranding: project.agentBranding || {}
  }
}];

// Build error log for pre-flight failure and reset status
const data = $('Code \u2014 Pre-flight Check').first().json;
const project = $('Code \u2014 Validate Project').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const message = data.message || 'Pre-flight validation failed';
const logEntry = `[${now}] \u2717 REEL ERROR: ${message}`;
const existingLog = project.pipelineLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  logEntry,
  fullLog: newLog,
  errorMessage: message,
  statusReset: 'videos_generated',
  projectRecordId: project.projectRecordId
} }];

// Return error response to webhook caller
const data = $('Code \u2014 Build Error (Pre-flight)').first().json;
return [{ json: {
  success: false,
  error: data.errorMessage,
  stage: 'pre-flight'
} }];

// Log dispatch to Pipeline Log before starting FFMPEG chain
const data = $('Code \u2014 Pre-flight Check').first().json;
const project = $('Code \u2014 Validate Project').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const logEntry = `[${now}] \u25b6 Dispatched: Reel Assembly (${data.clipCount} clips, music: ${data.musicTrack})`;
const existingLog = project.pipelineLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  fullLog: newLog,
  projectRecordId: data.projectRecordId
} }];

// V2: Download 4 video clips + music file from Google Drive
const data = $('Code \u2014 Pre-flight Check').first().json;
const workDir = data.workDir;
const driveFileIds = data.driveFileIds;
const musicDriveId = data.musicDriveId;

// Build download commands for 4 clips + 1 music file
const downloads = [];
for (let i = 0; i < driveFileIds.length; i++) {
  const fileId = driveFileIds[i];
  const outFile = `${workDir}/clip_${i + 1}.mp4`;
  // BUG-6 FIX: confirm=t bypasses Google virus scan page
  downloads.push(
    `curl -L -o ${outFile} "https://drive.google.com/uc?export=download&confirm=t&id=${fileId}" && ` +
    `file ${outFile} | grep -qv 'HTML' || (echo "FAIL: clip_${i + 1} is HTML" && exit 1)`
  );
}

// Download music
downloads.push(
  `curl -L -o ${workDir}/music.mp3 "https://drive.google.com/uc?export=download&confirm=t&id=${musicDriveId}" && ` +
  `file ${workDir}/music.mp3 | grep -qv 'HTML' || (echo "FAIL: music is HTML" && exit 1)`
);

const downloadCmd = downloads.join(' && ');

return [{
  json: {
    downloadCmd,
    workDir,
    projectRecordId: data.projectRecordId,
    reelRecordId: data.reelRecordId,
    brandName: data.brandName,
    clipCount: data.clipCount,
    pipelineLog: data.pipelineLog,
    industry: data.industry || '',
    agentBranding: data.agentBranding || {}
  }
}];

// Check if download succeeded
const result = $input.first().json;
const exitCode = result.exitCode;
const stderr = result.stderr || '';
const stdout = result.stdout || '';

if (exitCode !== 0) {
  const failMatch = stdout.match(/FAIL: (.+)/) || stderr.match(/FAIL: (.+)/);
  const detail = failMatch ? failMatch[1] : `exitCode=${exitCode}, stderr: ${stderr.slice(0, 200)}`;
  return [{ json: { error: true, message: `Download failed: ${detail}` } }];
}

return [{ json: { error: false } }];

// Build error log for download failure
const checkResult = $('Code \u2014 Check Download').first().json;
const project = $('Code \u2014 Validate Project').first().json;
const dispatchLog = $('Code \u2014 Build Dispatch Log').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const message = checkResult.message || 'Download failed';
const logEntry = `[${now}] \u2717 REEL ERROR: ${message}`;
const existingLog = dispatchLog.fullLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  logEntry,
  fullLog: newLog,
  errorMessage: message,
  statusReset: 'videos_generated',
  projectRecordId: project.projectRecordId,
  workDir: $('Code \u2014 Pre-flight Check').first().json.workDir
} }];

// Return error response for download failure
const data = $('Code \u2014 Build Error (Download)').first().json;
return [{ json: {
  success: false,
  error: data.errorMessage,
  stage: 'download'
} }];

// V2: Normalize 4 clips to 1080x1920 30fps h264
const workDir = $('Code \u2014 Build Download Commands').first().json.workDir;
const clipCount = $('Code \u2014 Build Download Commands').first().json.clipCount || 4;

const cmds = [];
for (let i = 1; i <= clipCount; i++) {
  cmds.push(
    `ffmpeg -y -i ${workDir}/clip_${i}.mp4 ` +
    `-vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2" ` +
    `-r 30 -c:v libx264 -crf 18 -pix_fmt yuv420p -an ${workDir}/norm_${i}.mp4`
  );
}
const normalizeCmd = cmds.join(' && ');

return [{
  json: {
    normalizeCmd,
    workDir
  }
}];

// Check if normalize succeeded
const result = $input.first().json;
const exitCode = result.exitCode;
const stderr = result.stderr || '';

if (exitCode !== 0) {
  const detail = stderr.slice(-300);
  return [{ json: { error: true, message: `Normalize failed (exitCode=${exitCode}): ${detail}` } }];
}

return [{ json: { error: false } }];

// Build error log for normalize failure
const checkResult = $('Code \u2014 Check Normalize').first().json;
const project = $('Code \u2014 Validate Project').first().json;
const dispatchLog = $('Code \u2014 Build Dispatch Log').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const message = checkResult.message || 'Normalize failed';
const logEntry = `[${now}] \u2717 REEL ERROR: ${message}`;
const existingLog = dispatchLog.fullLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  logEntry,
  fullLog: newLog,
  errorMessage: message,
  statusReset: 'videos_generated',
  projectRecordId: project.projectRecordId,
  workDir: $('Code \u2014 Pre-flight Check').first().json.workDir
} }];

// Return error response for normalize failure
const data = $('Code \u2014 Build Error (Normalize)').first().json;
return [{ json: {
  success: false,
  error: data.errorMessage,
  stage: 'normalize'
} }];

// V3: Dynamic FFMPEG stitch — ffprobe each clip for real duration
// T016: Added conditional RE branding overlay when industry === 'real-estate'
// Veo 3.1 clips vary 5-10s, can't hardcode offsets
const workDir = $('Code \u2014 Build Download Commands').first().json.workDir;
const fadeDur = 0.5;
const industry = ($('Code \u2014 Build Download Commands').first().json.industry || '').toLowerCase().trim();
const agentBranding = $('Code \u2014 Build Download Commands').first().json.agentBranding || {};
const isRealEstate = industry === 'real-estate';

// If RE, download agent logo for overlay
let logoDownloadCmd = '';
if (isRealEstate && agentBranding.logoUrl) {
  logoDownloadCmd = `curl -L -o ${workDir}/agent_logo.png "${agentBranding.logoUrl}" 2>/dev/null || true\n`;
}

// Build RE overlay filter components (applied after xfade, before output)
let reOverlayInputs = '';
let reOverlayFilter = '';
if (isRealEstate) {
  const brokerageName = (agentBranding.brokerageName || '').replace(/'/g, "'").replace(/"/g, '\\"');
  const mlsNumber = (agentBranding.mlsNumber || '').replace(/'/g, "'").replace(/"/g, '\\"');
  const hasLogo = !!agentBranding.logoUrl;

  // Build overlay filter chain: vfinal -> RE overlays -> vbranded
  let overlayChain = '';
  let currentLabel = 'vfinal';

  // Agent logo overlay (top-right corner, scaled to 120px wide)
  if (hasLogo) {
    reOverlayInputs = ' -i agent_logo.png';
    overlayChain += `[5:v]scale=120:-1[logo]; [${currentLabel}][logo]overlay=W-w-40:40[vlogo]; `;
    currentLabel = 'vlogo';
  }

  // Brokerage name text overlay (bottom-left)
  if (brokerageName) {
    overlayChain += `[${currentLabel}]drawtext=text='${brokerageName}':fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf:fontsize=28:fontcolor=white:borderw=2:bordercolor=black:x=40:y=H-160[vbrok]; `;
    currentLabel = 'vbrok';
  }

  // MLS number text overlay (bottom-left, below brokerage)
  if (mlsNumber) {
    overlayChain += `[${currentLabel}]drawtext=text='MLS\\# ${mlsNumber}':fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf:fontsize=22:fontcolor=white:borderw=2:bordercolor=black:x=40:y=H-120[vmls]; `;
    currentLabel = 'vmls';
  }

  // AI Generated Content disclosure (bottom-right, semi-transparent)
  overlayChain += `[${currentLabel}]drawtext=text='AI Generated Content':fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf:fontsize=18:fontcolor=white@0.6:borderw=1:bordercolor=black@0.4:x=W-w-40:y=H-60[vbranded]; `;
  currentLabel = 'vbranded';

  reOverlayFilter = overlayChain;
}

// Build a shell script that:
// 1. Probes each clip duration
// 2. Computes crossfade offsets dynamically
// 3. Builds and runs the ffmpeg command
// 4. (RE only) Applies branding overlays
const finalVideoLabel = isRealEstate ? 'vbranded' : 'vfinal';

const script = `#!/bin/bash
set -e
cd ${workDir}
${logoDownloadCmd}
# Probe durations
D1=$(ffprobe -v error -show_entries format=duration -of csv=p=0 norm_1.mp4)
D2=$(ffprobe -v error -show_entries format=duration -of csv=p=0 norm_2.mp4)
D3=$(ffprobe -v error -show_entries format=duration -of csv=p=0 norm_3.mp4)
D4=$(ffprobe -v error -show_entries format=duration -of csv=p=0 norm_4.mp4)

# Compute offsets: each offset = previous_offset + clip_duration - fade_duration
# First crossfade at: D1 - fade
OFF1=$(echo "$D1 - ${fadeDur}" | bc)
# Second crossfade at: OFF1 + D2 - fade
OFF2=$(echo "$OFF1 + $D2 - ${fadeDur}" | bc)
# Third crossfade at: OFF2 + D3 - fade
OFF3=$(echo "$OFF2 + $D3 - ${fadeDur}" | bc)
# Total duration for audio fade-out
TOTAL=$(echo "$OFF3 + $D4 - ${fadeDur}" | bc)
FADEOUT=$(echo "$TOTAL - 1.5" | bc)

echo "Durations: D1=$D1 D2=$D2 D3=$D3 D4=$D4"
echo "Offsets: OFF1=$OFF1 OFF2=$OFF2 OFF3=$OFF3 TOTAL=$TOTAL"

ffmpeg -y \\
  -i norm_1.mp4 -i norm_2.mp4 -i norm_3.mp4 -i norm_4.mp4 -i music.mp3${reOverlayInputs} \\
  -filter_complex \\
    "[0:v][1:v]xfade=transition=fade:duration=${fadeDur}:offset=$OFF1[v01]; \\
     [v01][2:v]xfade=transition=fade:duration=${fadeDur}:offset=$OFF2[v012]; \\
     [v012][3:v]xfade=transition=fade:duration=${fadeDur}:offset=$OFF3[vfinal]; \\
     ${reOverlayFilter}[4:a]volume=0.4,afade=t=in:st=0:d=1,afade=t=out:st=$FADEOUT:d=1.5[afinal]" \\
  -map "[${finalVideoLabel}]" -map "[afinal]" \\
  -c:v libx264 -crf 18 -profile:v main -level 4.1 \\
  -r 30 -pix_fmt yuv420p \\
  -c:a aac -b:a 128k \\
  -movflags +faststart \\
  -shortest \\
  reel_final.mp4
`;

return [{
  json: {
    ffmpegCmd: `bash -c '${script.replace(/'/g, "'\\\"'\\\"'")}'`,
    workDir
  }
}];

// Check if stitch succeeded
const result = $input.first().json;
const exitCode = result.exitCode;
const stderr = result.stderr || '';

if (exitCode !== 0) {
  const detail = stderr.slice(-300);
  return [{ json: { error: true, message: `Stitch failed (exitCode=${exitCode}): ${detail}` } }];
}

return [{ json: { error: false } }];

// Build error log for stitch failure
const checkResult = $('Code \u2014 Check Stitch').first().json;
const project = $('Code \u2014 Validate Project').first().json;
const dispatchLog = $('Code \u2014 Build Dispatch Log').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const message = checkResult.message || 'Stitch failed';
const logEntry = `[${now}] \u2717 REEL ERROR: ${message}`;
const existingLog = dispatchLog.fullLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  logEntry,
  fullLog: newLog,
  errorMessage: message,
  statusReset: 'videos_generated',
  projectRecordId: project.projectRecordId,
  workDir: $('Code \u2014 Pre-flight Check').first().json.workDir
} }];

// Return error response for stitch failure
const data = $('Code \u2014 Build Error (Stitch)').first().json;
return [{ json: {
  success: false,
  error: data.errorMessage,
  stage: 'stitch'
} }];

// Validate output with ffprobe
const workDir = $('Code \u2014 Build Download Commands').first().json.workDir;
const validateCmd = `ffprobe -v quiet -print_format json -show_format -show_streams ${workDir}/reel_final.mp4`;

return [{
  json: {
    validateCmd,
    workDir
  }
}];

// Parse ffprobe output and validate specs
// Returns error object instead of throwing
const result = $input.first().json;

if (result.exitCode !== 0) {
  return [{ json: { error: true, message: `Validate command failed (exitCode=${result.exitCode}): ${(result.stderr || '').slice(-200)}` } }];
}

const output = result.stdout;
let probe;
try {
  probe = JSON.parse(output);
} catch (e) {
  return [{ json: { error: true, message: `ffprobe output not valid JSON: ${output.slice(0, 200)}` } }];
}

const videoStream = probe.streams.find(s => s.codec_type === 'video');
const audioStream = probe.streams.find(s => s.codec_type === 'audio');

const errors = [];

if (videoStream) {
  if (videoStream.width !== 1080 || videoStream.height !== 1920) {
    errors.push(`Resolution: ${videoStream.width}x${videoStream.height} (expected 1080x1920)`);
  }
  if (videoStream.codec_name !== 'h264') {
    errors.push(`Video codec: ${videoStream.codec_name} (expected h264)`);
  }
} else {
  errors.push('No video stream found');
}

if (!audioStream) {
  errors.push('No audio stream found');
}

// Check file size
const fileSizeBytes = parseInt(probe.format.size || '0');
const fileSizeMB = fileSizeBytes / (1024 * 1024);
if (fileSizeMB > 100) {
  errors.push(`File size: ${fileSizeMB.toFixed(1)}MB (must be <100MB)`);
}

const duration = parseFloat(probe.format.duration || '0');

if (errors.length > 0) {
  return [{ json: { error: true, message: `Validation failed: ${errors.join('; ')}` } }];
}

const workDir = $('Code \u2014 Build Download Commands').first().json.workDir;

return [{
  json: {
    error: false,
    valid: true,
    duration: Math.round(duration),
    fileSizeMB: fileSizeMB.toFixed(1),
    resolution: `${videoStream.width}x${videoStream.height}`,
    codec: videoStream.codec_name,
    reelPath: `${workDir}/reel_final.mp4`,
    projectRecordId: $('Code \u2014 Build Download Commands').first().json.projectRecordId,
    reelRecordId: $('Code \u2014 Build Download Commands').first().json.reelRecordId,
    brandName: $('Code \u2014 Build Download Commands').first().json.brandName
  }
}];

// Build error log for validation failure
const checkResult = $('Code \u2014 Check Validation').first().json;
const project = $('Code \u2014 Validate Project').first().json;
const dispatchLog = $('Code \u2014 Build Dispatch Log').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const message = checkResult.message || 'Validation failed';
const logEntry = `[${now}] \u2717 REEL ERROR: ${message}`;
const existingLog = dispatchLog.fullLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  logEntry,
  fullLog: newLog,
  errorMessage: message,
  statusReset: 'videos_generated',
  projectRecordId: project.projectRecordId,
  workDir: $('Code \u2014 Pre-flight Check').first().json.workDir
} }];

// Return error response for validation failure
const data = $('Code \u2014 Build Error (Validate)').first().json;
return [{ json: {
  success: false,
  error: data.errorMessage,
  stage: 'validate'
} }];

// Build success Pipeline Log entry
const validation = $('Code \u2014 Check Validation').first().json;
const driveId = $('Google Drive \u2014 Upload Reel').first().json.id;
const dispatchLog = $('Code \u2014 Build Dispatch Log').first().json;
const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
const driveUrl = `https://drive.google.com/file/d/${driveId}/view`;
const logEntry = `[${now}] \u2713 Reel assembled (${validation.duration}s, ${validation.fileSizeMB}MB) \u2192 ${driveUrl}`;
const existingLog = dispatchLog.fullLog || '';
const newLog = existingLog ? existingLog + '\n' + logEntry : logEntry;

return [{ json: {
  fullLog: newLog,
  projectRecordId: validation.projectRecordId
} }];

// Final success response to webhook caller
const validation = $('Code \u2014 Check Validation').first().json;
const driveId = $('Google Drive \u2014 Upload Reel').first().json.id;
return [{ json: {
  success: true,
  duration: validation.duration,
  fileSizeMB: validation.fileSizeMB,
  resolution: validation.resolution,
  driveUrl: `https://drive.google.com/file/d/${driveId}/view`,
  reelRecordId: validation.reelRecordId
} }];
